def seed(db: Session):
    count = 0
    for data in MECHANISMS:
        if db.query(Mechanism).filter(Mechanism.id == data["id"]).first():
            continue
        steps = data.pop("steps")
        mechanism = Mechanism(**data)
        db.add(mechanism)
        db.flush()
        for i, step in enumerate(steps):
            db.add(MechanismStep(mechanism_id=mechanism.id, order_num=i, step_text=step))
        count += 1
    db.commit()
    print(f"  Mechanisms: {count} seeded")
